#include &lt;cmath&gt;#include &lt;iostream&gt; using namespace std; typedef long long ll; int main() { int a, b, c, d; cin &gt;&gt; a &gt;&gt; b &gt;&gt; c &gt;&gt; d; if (b &gt;= c * d) puts(&#34;-1&#34;); else printf(&#34;%lld\n&#34;, (ll)ceil(a / (d * c - b))); return 0; } C-Many Segments 暴力法, 每两段区间直接进行判断 $O(N ^ {2}) $; 对 4 种区间情况，进行了一点小处理
#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;iostream&gt;#define x first #define y second  using namespace std; typedef long long ll; const int M = 2021; typedef pair&lt;int, int&gt; PII; PII num[M]; int t[M]; void f(int op, double &amp;a, double &amp;b) { //处理区间开闭  if (op == 2) b -= 0.1; else if (op == 3) a += 0.1; else if (op == 4) { a += 0.1, b -= 0.1; } } bool cheak(int i, int j) { //判断函数  double a = num[i].x, b = num[i].y, c = num[j].x, d = num[j].y; f(t[i], a, b); f(t[j], c, d); if (a &lt;= c &amp;&amp; b &gt;= c) return true; else if (c &lt;= a &amp;&amp; d &gt;= a) return true; return false; } int main() { int n; scanf(&#34;%d&#34;, &amp;n); for (int i = 1; i &lt;= n; i++) scanf(&#34;%d%d%d&#34;, &amp;t[i], &amp;num[i].x, &amp;num[i].y); int cnt = 0; for (int i = 1; i &lt;= n; i++) { for (int j = i + 1; j &lt;= n; j++) { if (cheak(i, j)) { cnt++; } } } printf(&#34;%d\n&#34;, cnt); return 0; } 还可以用离散化 + 扫描线法 ${\large O}(N \log{N}) $; 预处理区间边界，用 map 实现离散化，再扫描线求出答案；
#include &lt;iostream&gt;#include &lt;map&gt;#define x first #define y second  using namespace std; typedef long long ll; const int M = 2021; typedef pair&lt;ll, ll&gt; Pll; typedef pair&lt;int, int&gt; PII; Pll num[M]; int t[M]; void f(int op, ll &amp;a, ll &amp;b) { //处理区间边界  a *= 10, b *= 10; if (op == 2) b -= 1; else if (op == 3) a += 1; else if (op == 4) { a += 1; b -= 1; } } int main() { int n, cnt = 0; scanf(&#34;%d&#34;, &amp;n); map&lt;ll, PII&gt; mp; for (int i = 1; i &lt;= n; i++) { scanf(&#34;%d%lld%lld&#34;, &amp;t[i], &amp;num[i].x, &amp;num[i].y); f(t[i], num[i].x, num[i].y); mp[num[i].x].x++, mp[num[i].y].y++; //记录线段的始，末  } int last = 0; // 当前“延续”的线段  for (auto i : mp) { cnt += last * i.y.x; //计算新出现的与旧的线段的交叉  cnt += (i.y.x - 1) * (i.y.x) / 2;//计算新线段之间的交叉  last += i.y.x - i.y.y; } printf(&#34;%d\n&#34;, cnt); return 0; } 思考：如果是三条线段重叠，则每次更新可能是 $$ \binom{last}{1} \binom{new}{2} + \binom{last}{2}\binom{new}{1} + \binom{new}{3} $$ 依此类推……
E - Mod i #include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;iostream&gt; using namespace std; typedef long long ll; const ll MOD = 1e9 + 7, M = 3030; ll num[M], S[M], dp[M][M], r[M]; int main(){ int N; scanf(&#34;%d&#34;, &amp;N); for (int i = 1; i &lt;= N; i++) scanf(&#34;%lld&#34;, &amp;num[i]); for (int i = 1; i &lt;= N; i++){ S[i] = S[i - 1] + num[i]; } ll ans = 0; dp[0][0] = 1; for (int i = 1; i &lt;= N; i++){ memset(r, 0, sizeof r); for (int j = 0; j &lt;= N; j++){ dp[i][j] = r[S[j] % i]; r[S[j] % i] += dp[i - 1][j]; r[S[j] % i] %= MOD; } ans += dp[i][N]; ans %= MOD; } printf(&#34;%lld\n&#34;, ans); return 0; }
